          <ThemedText className="mb-1 text-3xl font-bold">Welcome back</ThemedText>
          <ThemedText className="mb-14 text-light-subtext dark:text-dark-subtext">
            Sign in to your account
          </ThemedText>

          <Input
            label="Email"
            value={email}
            onChangeText={(text) => {
              setEmail(text);
              if (emailError) validateEmail(text);
            }}
            error={emailError}
            keyboardType="email-address"
            autoCapitalize="none"
            autoComplete="email"
            containerClassName="mb-4"
          />

          <Input
            label="Password"
            value={password}
            onChangeText={(text) => {
              setPassword(text);
              if (passwordError) validatePassword(text);
            }}
            error={passwordError}
            isPassword
            autoCapitalize="none"
            containerClassName="mb-4"
          />

          <Link
            className="mb-4 text-sm text-black underline dark:text-white"
            href="/screens/forgot-password">
            Forgot Password?
          </Link>

          <Button
            title="Login"
            onPress={handleLogin}
            loading={isLoading}
            size="large"
            className="mb-6"
          />

          <View className="flex-row justify-center">
