);

// Rating Item Component
interface RatingItemProps {
  label: string;
  rating: number;
}

const RatingItem = ({ label, rating }: RatingItemProps) => (
  <View className="flex-row items-center justify-between py-2">
    <ThemedText className="text-sm">{label}</ThemedText>
    <View className="flex-row items-center">
      <ShowRating rating={rating} size="sm" />
    </View>
  </View>
);

export default PropertyDetail;

import { useNavigation } from '@react-navigation/native';
import React, { useState } from 'react';
import { View, ScrollView, Pressable, TouchableOpacity } from 'react-native';

import AnimatedView from '@/components/AnimatedView';
import { Button } from '@/components/Button';
import Header from '@/components/Header';
import Icon from '@/components/Icon';
import ThemedScroller from '@/components/ThemeScroller';
import ThemedText from '@/components/ThemedText';

interface Currency {
  code: string;
  title: string;
}

const CurrencyScreen = () => {
  const navigation = useNavigation();
  const [selectedCurrency, setSelectedCurrency] = useState('USD');

  const currencies: Currency[] = [
    { code: 'USD', title: 'United States Dollar' },
    { code: 'EUR', title: 'Euro' },
    { code: 'GBP', title: 'British Pound' },
    { code: 'CAD', title: 'Canadian Dollar' },
    { code: 'AUD', title: 'Australian Dollar' },
    { code: 'CHF', title: 'Swiss Franc' },
    { code: 'JPY', title: 'Japanese Yen' },
    { code: 'CNY', title: 'Chinese Yuan' },
    { code: 'INR', title: 'Indian Rupee' },
    { code: 'BRL', title: 'Brazilian Real' },
    { code: 'ZAR', title: 'South African Rand' },
    { code: 'MXN', title: 'Mexican Peso' },
  ];

  const saveSettings = () => {
    // Here you would save the selected currency
    navigation.goBack();
  };

  return (
    <View className="bg-light-bg dark:bg-dark-bg flex-1">
      <Header
        showBackButton
        title="Currency"
        rightComponents={[<Button title="Save" onPress={saveSettings} />]}
      />
      <ThemedScroller>
        {currencies.map((currency) => (
          <CurrencyItem
            key={currency.code}
            title={currency.title}
            code={currency.code}
            selected={selectedCurrency === currency.code}
            onSelect={() => setSelectedCurrency(currency.code)}
          />
        ))}
      </ThemedScroller>
    </View>
  );
};

interface CurrencyItemProps {
  title: string;
  code: string;
  selected: boolean;
  onSelect: () => void;
}

const CurrencyItem = ({ title, code, selected, onSelect }: CurrencyItemProps) => {
  return (
    <TouchableOpacity
      activeOpacity={0.8}
      onPress={onSelect}
      className={`flex-row items-center justify-between border-b border-light-secondary py-4 dark:border-dark-secondary ${selected ? 'opacity-100' : 'opacity-100 '}`}>
      <View>
        <ThemedText className="text-lg font-bold">{code}</ThemedText>
        <ThemedText className="text-light-subtext dark:text-dark-subtext">{title}</ThemedText>
      </View>
      {selected && (
        <AnimatedView animation="bounceIn" duration={500}>
          <Icon name="Check" size={25} />
        </AnimatedView>
      )}
    </TouchableOpacity>
  );
};

export default CurrencyScreen;

import { useNavigation } from '@react-navigation/native';
import React, { useState } from 'react';
import { View, ScrollView } from 'react-native';

import { Button } from '@/components/Button';
import Header from '@/components/Header';
import ThemedScroller from '@/components/ThemeScroller';
import ThemedText from '@/components/ThemedText';
import Switch from '@/components/forms/Switch';
import Section from '@/components/layout/Section';

const NotificationsScreen = () => {
  const navigation = useNavigation();

  const [notifications, setNotifications] = useState({
    pushEnabled: true,
    bookingUpdates: true,
    hostMessages: true,
    paymentConfirmations: true,
    reviewRequests: true,
    checkInReminders: true,
    specialOffers: false,
    hostPromotions: false,
    travelTips: false,
    marketingEmails: false,
  });

  const handleToggle = (setting: keyof typeof notifications, value: boolean) => {
    setNotifications((prev) => ({
      ...prev,
      [setting]: value,
    }));
  };

  const saveSettings = () => {
    navigation.goBack();
  };

  return (
    <View className="bg-light-bg dark:bg-dark-bg flex-1">
      <Header
        showBackButton
        rightComponents={[<Button title="Save changes" onPress={saveSettings} />]}
      />
      <ThemedScroller>
        <Section
          titleSize="3xl"
          className="mt-10 pb-10"
          title="Notifications"
          subtitle="Stay updated on your bookings and travel plans"
        />

        <View className="mb-8">
          <ThemedText className="mb-4 text-lg font-bold">Booking & Travel</ThemedText>

          <Switch
            label="Booking Updates"
            description="Confirmations, changes, and cancellations"
            value={notifications.bookingUpdates}
            onChange={(value) => handleToggle('bookingUpdates', value)}
            disabled={!notifications.pushEnabled}
            className="mb-4"
          />

          <Switch
            label="Host Messages"
            description="Messages from your hosts and property owners"
            value={notifications.hostMessages}
            onChange={(value) => handleToggle('hostMessages', value)}
            disabled={!notifications.pushEnabled}
            className="mb-4"
          />

          <Switch
            label="Payment Confirmations"
            description="Receipts and payment processing updates"
