import { AntDesign } from '@expo/vector-icons';
import { router } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
import React, { useState } from 'react';
import { View, Pressable, SafeAreaView, Platform, Alert, ActivityIndicator } from 'react-native';

import Icon from '@/components/Icon';

import { useSafeAreaInsets } from 'react-native-safe-area-context';

import useThemeColors from '../contexts/ThemeColors';

import { useAuth } from '@/app/contexts/AuthContext';
import ThemeToggle from '@/components/ThemeToggle';
import ThemedText from '@/components/ThemedText';

export default function WelcomeScreen() {
  const colors = useThemeColors();
  const insets = useSafeAreaInsets();
  const { signInWithGoogle, signInWithApple } = useAuth();
  const [loadingProvider, setLoadingProvider] = useState<string | null>(null);

  const handleGoogleSignIn = async () => {
    try {
      setLoadingProvider('google');
      await signInWithGoogle();
    } catch (error: any) {
      Alert.alert('Sign-In Error', error.message || 'Failed to sign in with Google');
    } finally {
      setLoadingProvider(null);
    }
  };

  const handleAppleSignIn = async () => {
    try {
      setLoadingProvider('apple');
      await signInWithApple();
    } catch (error: any) {
      if (error?.code === 'ERR_REQUEST_CANCELED') return;
      Alert.alert('Sign-In Error', error.message || 'Failed to sign in with Apple');
    } finally {
      setLoadingProvider(null);
    }
  };

  const isLoading = loadingProvider !== null;

  return (
    <SafeAreaView
      style={{ paddingTop: insets.top, paddingBottom: insets.bottom }}
      className="flex-1 bg-light-primary dark:bg-dark-primary">
      <View className="relative flex-1 bg-light-primary dark:bg-dark-primary">
        <View className="w-full flex-row justify-end px-4 pt-2">
          <ThemeToggle />
        </View>

        <View className="flex w-full flex-1 flex-col items-start justify-center gap-2 px-global pb-20">
          {/* Logo / Brand */}
          <View className="mb-8">
            <View className="mb-4 h-16 w-16 items-center justify-center rounded-2xl bg-highlight">
              <Icon name="Trophy" size={32} strokeWidth={1.8} className="text-white" />
            </View>
            <ThemedText className="text-4xl font-bold">HDC Sports</ThemedText>
            <ThemedText className="mt-1 text-base text-light-subtext dark:text-dark-subtext">
              Book sports facilities across Hulhumalé
            </ThemedText>
          </View>

          {/* Google Sign-In */}
          <Pressable
            onPress={handleGoogleSignIn}
            disabled={isLoading}
            className={`flex w-full flex-row items-center justify-center rounded-2xl border border-light-subtext/30 py-4 dark:border-dark-subtext/30 ${isLoading ? 'opacity-50' : ''}`}>
            <View className="top-4.5 absolute left-4">
              {loadingProvider === 'google' ? (
                <ActivityIndicator size="small" color={colors.text} />
              ) : (
                <AntDesign name="google" size={22} color={colors.text} />
              )}
            </View>
            <ThemedText className="pr-2 text-base font-medium">Continue with Google</ThemedText>
          </Pressable>

          {/* Apple Sign-In (iOS only) */}
          {Platform.OS === 'ios' && (
            <Pressable
              onPress={handleAppleSignIn}
              disabled={isLoading}
              className={`flex w-full flex-row items-center justify-center rounded-2xl border border-light-subtext/30 py-4 dark:border-dark-subtext/30 ${isLoading ? 'opacity-50' : ''}`}>
              <View className="top-4.5 absolute left-4">
                {loadingProvider === 'apple' ? (
                  <ActivityIndicator size="small" color={colors.text} />
                ) : (
                  <AntDesign name="apple1" size={22} color={colors.text} />
                )}
              </View>
              <ThemedText className="pr-2 text-base font-medium">Continue with Apple</ThemedText>
            </Pressable>
          )}

          {/* Skip for now (dev bypass) */}
          <Pressable
            onPress={() => router.replace('/(tabs)/(home)')}
            className="mt-2 w-full items-center py-3">
            <ThemedText className="text-sm font-medium text-highlight">
              Continue as guest
            </ThemedText>
          </Pressable>

          <View className="mt-4 px-2">
            <ThemedText className="text-center text-xs text-light-subtext dark:text-dark-subtext">
              By continuing, you agree to HDC's Terms of Service and Privacy Policy. Only registered
              sports teams can book facilities.
            </ThemedText>
          </View>
        </View>
      </View>
    </SafeAreaView>
  );
}

import { styled } from 'nativewind';
import React, { useState, useCallback, useRef, useEffect } from 'react';
import {
  View,
  TouchableWithoutFeedback,
  ViewStyle,
  TextStyle,
  Dimensions,
  LayoutChangeEvent,
} from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  interpolate,
  Extrapolate,
  runOnJS,
} from 'react-native-reanimated';

import Icon, { IconName } from './Icon';

import useThemeColors from '@/app/contexts/ThemeColors';

const StyledAnimatedView = styled(Animated.View);
const StyledView = styled(View);
const StyledTouchableWithoutFeedback = styled(TouchableWithoutFeedback);
const { width: windowWidth } = Dimensions.get('window');
type AnimatedFabProps = {
  icon: IconName;
  children: React.ReactNode;
  position?: 'bottomRight' | 'bottomLeft' | 'topRight' | 'topLeft';
  iconSize?: number;
  backgroundColor?: string;
  iconColor?: string;
  className?: string;
  contentClassName?: string;
  iconClassName?: string;
  style?: ViewStyle;
  onOpen?: () => void;
  onClose?: () => void;
};

const AnimatedFab: React.FC<AnimatedFabProps> = ({
  icon,
  children,
  position = 'bottomRight',
  iconSize = 24,
  backgroundColor,
  iconColor,
  className,
  contentClassName,
  iconClassName,
  onOpen,
  onClose,
  style,
}) => {
  const colors = useThemeColors();
  const [isOpen, setIsOpen] = useState(false);

  // Default size of the FAB in collapsed state
  const baseSize = iconSize * 2;

  // Improved content height measurement
  const [contentHeight, setContentHeight] = useState(baseSize * 2);
  const contentMeasureRef = useRef<View>(null);
  const [isContentMeasured, setIsContentMeasured] = useState(false);

  // Animation values
  const animation = useSharedValue(0);

  // Cleanup animation value on unmount
  useEffect(() => {
    return () => {
      // Reset animation value before cleanup
      animation.value = 0;
    };
  }, []);

  // Reset animation when theme changes
  useEffect(() => {
    if (isOpen) {
      animation.value = withTiming(1, { duration: 300 });
    } else {
      animation.value = withTiming(0, { duration: 300 });
    }
  }, [colors.isDark]);

  // Measure content using an invisible clone
  useEffect(() => {
    if (contentMeasureRef.current && !isContentMeasured) {
      setTimeout(() => {
        if (contentMeasureRef.current) {
          contentMeasureRef.current.measure((x, y, width, height) => {
            if (height > 0) {
              // Add padding and set minimum height
              const newHeight = Math.max(baseSize * 1, height + 0);
              setContentHeight(newHeight);
              setIsContentMeasured(true);
            }
          });
        }
      }, 100);
    }
  }, [contentMeasureRef.current, isContentMeasured, baseSize]);

  // Handle toggle state
  const toggleOpen = useCallback(() => {
    const newValue = !isOpen;
    setIsOpen(newValue);

    // Run animation
    animation.value = withTiming(newValue ? 1 : 0, { duration: 300 });

    // Trigger callbacks if provided
    if (newValue && onOpen) {
      onOpen();
    } else if (!newValue && onClose) {
      onClose();
    }
  }, [isOpen, animation, onOpen, onClose]);

  // Position classes based on the position prop
  const getPositionClasses = (): string => {
    switch (position) {
      case 'bottomRight':
        return 'bottom-4 right-4';
      case 'bottomLeft':
        return 'bottom-4 left-4';
      case 'topRight':
        return 'top-4 right-4';
      case 'topLeft':
        return 'top-4 left-4';
      default:
        return 'bottom-4 right-4';
    }
  };

  // Animated styles for the container
  const containerStyle = useAnimatedStyle(() => {
    // Width expands from a circle to a rectangle
    const width = interpolate(
      animation.value,
      [0, 1],
      [baseSize, windowWidth - 30],
      Extrapolate.CLAMP
    );

    // Use the measured content height for the expanded state
    const height = interpolate(
      animation.value,
      [0, 1],
      [baseSize, contentHeight],
      Extrapolate.CLAMP
    );

    // Border radius changes from circle to rounded rectangle
    const borderRadius = interpolate(
      animation.value,
      [0, 1],
      [baseSize / 2, 12],
      Extrapolate.CLAMP
    );

    return {
      width,
      height,
      borderRadius,
    };
  });

  // Animated styles for the icon
  const iconAnimatedStyle = useAnimatedStyle(() => {
    const rotate = interpolate(
      animation.value,
      [0, 1],
      [0, 45], // Rotate 45 degrees when open
      Extrapolate.CLAMP
    );

    const opacity = interpolate(animation.value, [0, 0.5, 1], [1, 0.3, 0], Extrapolate.CLAMP);

    return {
      transform: [{ rotate: `${rotate}deg` }],
      opacity,
    };
  });

  // Animated styles for the content
  const contentAnimatedStyle = useAnimatedStyle(() => {
    const opacity = interpolate(animation.value, [0, 0.7, 1], [0, 0, 1], Extrapolate.CLAMP);

    const translateY = interpolate(animation.value, [0, 1], [20, 0], Extrapolate.CLAMP);

    return {
      opacity,
      transform: [{ translateY }],
    };
  });

  const bgColor = backgroundColor || colors.highlight;

  return (
    <>
      {/* Hidden content measure view */}
      <StyledView
        className="pointer-events-none absolute left-[-9999px] opacity-0"
        style={{ width: windowWidth - 30 }}
        ref={contentMeasureRef}>
        <View className="pb-10">{children}</View>
      </StyledView>

      <TouchableWithoutFeedback>
        <StyledAnimatedView
          className={`absolute z-10 items-center justify-center bg-black shadow-md shadow-black/30 dark:bg-white
            ${getPositionClasses()}
            ${className}`}
          style={[
            containerStyle,
            //{ backgroundColor: bgColor }
          ]}>
          <TouchableWithoutFeedback onPress={toggleOpen}>
            <StyledAnimatedView
              className={`absolute z-20 items-center justify-center ${iconClassName}`}
              style={[iconAnimatedStyle, style]}>
              <Icon name={icon} size={iconSize} color={iconColor || 'white'} />
            </StyledAnimatedView>
          </TouchableWithoutFeedback>

          {/**THIS IS CONTENT OF THE FAB */}
          <StyledAnimatedView
            className={`absolute z-10 h-full w-full items-start justify-start p-6 pb-0 ${contentClassName}`}
            style={[contentAnimatedStyle, style]}>
            <Icon
              name="X"
              size={24}
              color="white"
              className="absolute right-2 top-2 z-50"
              onPress={toggleOpen}
            />
            {children}
          </StyledAnimatedView>
        </StyledAnimatedView>
      </TouchableWithoutFeedback>
    </>
  );
};

export default AnimatedFab;

import { useIsFocused } from '@react-navigation/native';
import React, { useEffect, memo, useRef, useState } from 'react';
import {
  Animated,
  ViewStyle,
  StyleProp,
  EasingFunction,
  Easing,
  View,
  LayoutChangeEvent,
  Dimensions,
  InteractionManager,
} from 'react-native';

export type AnimationType =
  | 'fadeIn'
  | 'scaleIn'
  | 'slideInBottom'
  | 'slideInRight'
  | 'slideInLeft'
  | 'slideInTop'
  | 'bounceIn'
  | 'flipInX'
  | 'zoomInRotate'
  | 'rotateIn';

interface AnimatedViewProps {
  children?: React.ReactNode;
  animation: AnimationType;
  duration?: number;
  delay?: number;
  easing?: EasingFunction;
  style?: StyleProp<ViewStyle>;
  className?: string;
  playOnlyOnce?: boolean;
  triggerOnVisible?: boolean; // Only animate when component becomes visible in viewport
  visibilityThreshold?: number; // Pixels needed to be visible to trigger (default: 50)
}

// Function to compare props for pure rendering
const propsAreEqual = (prevProps: AnimatedViewProps, nextProps: AnimatedViewProps) => {
  // Always re-render when in development mode to support hot reloading
  if (__DEV__) {
    return false;
  }

  // In production, optimize rendering:
  // If animation, duration, delay, or easing changes, we should re-render
  if (
    prevProps.animation !== nextProps.animation ||
    prevProps.duration !== nextProps.duration ||
    prevProps.delay !== nextProps.delay ||
    prevProps.easing !== nextProps.easing
  ) {
    return false;
  }

  // Basic check for children changes (reference equality)
  if (prevProps.children !== nextProps.children) {
    return false;
  }

  // Check style prop changes
  if (prevProps.style !== nextProps.style) {
    return false;
  }

  // Check className changes
  if (prevProps.className !== nextProps.className) {
    return false;
  }

  // No changes detected, avoid re-render
  return true;
};

function AnimatedViewComponent({
  children,
  animation,
  duration = 300,
  delay = 0,
  easing = Easing.bezier(0.4, 0, 0.2, 1),
  style,
  className,
  playOnlyOnce = false,
  triggerOnVisible = false,
  visibilityThreshold = 30, // Default to 50px visibility required
}: AnimatedViewProps) {
  const animatedValue = useRef(new Animated.Value(0)).current;
  const isFocused = useIsFocused();
  const hasAnimatedOnce = useRef(false);
  const viewRef = useRef<View>(null);
  // Important: initial state is false if triggerOnVisible is true, otherwise we animate immediately
  const [isVisible, setIsVisible] = useState(false);
  const { height: windowHeight } = Dimensions.get('window');
  const measureInterval = useRef<NodeJS.Timeout | null>(null);
  const isFirstRender = useRef(true);

  // Initialize with visibility detection - but delayed to ensure proper measurement
  useEffect(() => {
    if (!triggerOnVisible) {
      // If not using visibility detection, just set to visible
      setIsVisible(true);
      return;
    }

    // Important: For first render, ensure layout is complete before measuring
    // and we're actually checking visibility correctly
    if (isFirstRender.current) {
      isFirstRender.current = false;

      // Wait for interactions to complete (navigation, etc)
      InteractionManager.runAfterInteractions(() => {
        // Slight delay to ensure component is fully mounted and measurable
        setTimeout(() => {
          checkVisibility();
        }, 0);
      });
    }

    return () => {
      if (measureInterval.current) {
        clearInterval(measureInterval.current);
      }
    };
  }, [triggerOnVisible]);

  // Function to check visibility by measuring the component
  const checkVisibility = () => {
    if (!viewRef.current || hasAnimatedOnce.current) return;

    // Clear any existing interval
    if (measureInterval.current) {
      clearInterval(measureInterval.current);
      measureInterval.current = null;
    }

    // Start periodic measuring until visible
    measureInterval.current = setInterval(() => {
      if (!viewRef.current || hasAnimatedOnce.current) {
        if (measureInterval.current) {
          clearInterval(measureInterval.current);
        }
        return;
      }

      // Measure component position relative to window
      viewRef.current.measure((x, y, width, height, pageX, pageY) => {
        // Calculate if it's in viewport (at least visibilityThreshold pixels visible)
        // Element is in view if its top is within screen bounds OR its bottom is within screen bounds
        const isElementVisible =
          // Either top of element is visible in viewport
          (pageY >= 0 && pageY <= windowHeight - visibilityThreshold) ||
          // OR bottom of element is visible in viewport
          (pageY + height >= visibilityThreshold && pageY + height <= windowHeight) ||
          // OR element completely covers viewport
          (pageY < 0 && pageY + height > windowHeight);

        if (isElementVisible) {
          setIsVisible(true);
          if (measureInterval.current) {
            clearInterval(measureInterval.current);
            measureInterval.current = null;
          }
        }
      });
    }, 0);
  };

  // Handle layout to initialize position tracking
  const handleLayout = (e: LayoutChangeEvent) => {
    if (!triggerOnVisible || hasAnimatedOnce.current) return;

    // After layout, start visibility detection if not already started
    if (!isVisible && !measureInterval.current) {
      checkVisibility();
    }
  };

  // Start animation when conditions are met
  useEffect(() => {
    // Skip if not focused or not visible
    if (!isFocused || !isVisible) return;

    // If playOnlyOnce is true and animation has played once, don't play again
    if (playOnlyOnce && hasAnimatedOnce.current) return;

    // Add a unique identifier for this animation to prevent duplicate animations
    const animationId = Date.now();
    const currentAnimationId = animationId;

    // Reset animation value
    animatedValue.setValue(0);

    // Start animation
    Animated.timing(animatedValue, {
      toValue: 1,
      duration,
      delay,
      easing,
      useNativeDriver: true,
    }).start(({ finished }) => {
      // Only mark as animated if this is the most recent animation and it finished
      if (finished && currentAnimationId === animationId) {
        hasAnimatedOnce.current = true;
      }
    });

    // Return cleanup function
    return () => {
      // Animation will be cleaned up automatically by React Native
    };
    // Restrict dependencies to only those that should trigger a re-animation
    // Specifically exclude anything related to parent component state like header visibility
  }, [isFocused, isVisible, playOnlyOnce]);

  const getAnimationStyle = (): any => {
    const baseStyle: ViewStyle = {};

    switch (animation) {
      case 'fadeIn':
        return {
          opacity: animatedValue,
        };

      case 'scaleIn':
        return {
          //opacity: animatedValue,
          transform: [
            {
              scale: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: [0.95, 1],
              }),
            },
          ],
        };

      case 'slideInBottom':
        return {
          opacity: animatedValue,
          transform: [
            {
              translateY: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: [50, 0],
              }),
            },
          ],
        };

      case 'slideInRight':
        return {
          opacity: animatedValue,
          transform: [
            {
              translateX: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: [100, 0],
              }),
            },
          ],
        };

      case 'slideInLeft':
        return {
          opacity: animatedValue,
          transform: [
            {
              translateX: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: [-100, 0],
              }),
            },
          ],
        };

      case 'slideInTop':
        return {
          opacity: animatedValue,
          transform: [
            {
              translateY: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: [-100, 0],
              }),
            },
          ],
        };

      case 'bounceIn':
        return {
          opacity: animatedValue,
          transform: [
            {
              scale: animatedValue.interpolate({
                inputRange: [0, 0.6, 0.8, 1],
                outputRange: [0.3, 1.1, 0.9, 1],
              }),
            },
          ],
        };

      case 'flipInX':
        return {
          opacity: animatedValue,
          transform: [
            {
              rotateX: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: ['90deg', '0deg'],
              }),
            },
          ],
        };

      case 'zoomInRotate':
        return {
          //opacity: animatedValue,
          transform: [
            {
              rotate: animatedValue.interpolate({
                inputRange: [0, 1],
                outputRange: ['-45deg', '0deg'],
              }),
            },
          ],
        };

      case 'rotateIn':
        return {
          //opacity: animatedValue,
          transform: [
            {
              rotate: animatedValue.interpolate({
                inputRange: [0, 0.5, 1],
                outputRange: ['0deg', '50deg', '0deg'],
              }),
            },
          ],
        };

      default:
        return baseStyle;
    }
  };

  // Initial style for elements waiting to be visible
  const initialHiddenStyle: ViewStyle =
    triggerOnVisible && !isVisible
      ? {
          opacity: 0, // Keep element hidden until it's ready to animate
        }
      : {};

  return (
    <View
      ref={viewRef}
      className={className}
      style={[style, initialHiddenStyle]}
      onLayout={handleLayout}
      collapsable={false}>
      <Animated.View style={[getAnimationStyle(), style]} className={className}>
        {children}
      </Animated.View>
    </View>
  );
}

// Export a memoized version of the component
export default memo(AnimatedViewComponent, propsAreEqual);

import { Link, router } from 'expo-router';
import React from 'react';
import { Image, Pressable, View, Text, ViewStyle, ImageSourcePropType } from 'react-native';

import ThemedText from './ThemedText';

type AvatarProps = {
  size?: 'xxs' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'xxl';
  src?: string | ImageSourcePropType; // Can be a URL string or required image
  name?: string; // for displaying initials if no image
  border?: boolean;
  bgColor?: string; // Optional background color
  onPress?: () => void; // Optional onPress for Pressable or Link
  link?: string; // Optional URL for Link
  className?: string;
  style?: ViewStyle;
};

const Avatar: React.FC<AvatarProps> = ({
  size = 'md',
  src,
  name,
  border = false,
  bgColor = 'bg-light-secondary dark:bg-dark-secondary',
  onPress,
  link,
  className,
  style,
}) => {
  // Avatar size styles
  const sizeMap = {
    xxs: 'w-7 h-7',
    xs: 'w-8 h-8',
    sm: 'w-10 h-10',
    md: 'w-12 h-12',
    lg: 'w-16 h-16',
    xl: 'w-20 h-20',
    xxl: 'w-24 h-24',
  };

  // Define border size and color if enabled
  const borderStyle = border ? 'border-2 border-light-secondary dark:border-dark-secondary' : '';

  // Component for initials if image is not provided
  const renderInitials = () => {
    if (!name) return null;
    const initials = name
      .split(' ')
      .map((part) => part[0].toUpperCase())
      .join('');
    return <ThemedText className=" text-center font-medium">{initials}</ThemedText>;
  };

  // Convert the src prop to an appropriate Image source prop
  const getImageSource = (): ImageSourcePropType => {
    if (!src) {
      // Return a transparent 1x1 pixel as fallback instead of null
      return {
        uri: 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=',
      };
    }

    // If src is a string (URL), return it as a uri object
    if (typeof src === 'string') {
      return { uri: src };
    }

    // Otherwise it's already a required image or other valid source
    return src;
  };

  const avatarContent = (
    <View
      className={`flex-shrink-0 rounded-full ${bgColor} ${sizeMap[size]} ${borderStyle} items-center justify-center ${className}`}
      style={style}>
      {src ? (
        <Image source={getImageSource()} className="h-full w-full rounded-full object-cover" />
      ) : (
        renderInitials()
      )}
    </View>
  );

  if (link) {
    return <Pressable onPress={() => router.push(link)}>{avatarContent}</Pressable>;
  }

  return onPress ? <Pressable onPress={onPress}>{avatarContent}</Pressable> : avatarContent;
};

export default Avatar;

import { Feather } from '@expo/vector-icons';
import { useRef } from 'react';
import { Pressable, Text, View, Animated, Easing } from 'react-native';

import Icon from './Icon';

import { useBusinessMode } from '@/app/contexts/BusinesModeContext';
import useThemeColors from '@/app/contexts/ThemeColors';

const BusinessSwitch = () => {
  const { isBusinessMode, toggleMode } = useBusinessMode();
  const colors = useThemeColors();
  const rotationAnim = useRef(new Animated.Value(0)).current;

  const handlePress = () => {
    // Reset the rotation value to 0 if it's at 1
    rotationAnim.setValue(0);

    // Animate to 1 (which represents 360 degrees)
    Animated.timing(rotationAnim, {
      toValue: 1,
      duration: 1000,
      easing: Easing.out(Easing.cubic),
      useNativeDriver: true,
    }).start();

    // Toggle the business mode
    toggleMode();
  };

  // Create the rotation interpolation
  const spin = rotationAnim.interpolate({
    inputRange: [0, 1],
    outputRange: ['0deg', '360deg'],
  });

  return (
    <View className="absolute bottom-0 w-full items-center justify-center pb-4">
      <Pressable
        onPress={handlePress}
        style={{
          shadowColor: '#000', // iOS shadow color
          shadowOffset: { width: 0, height: 2 }, // iOS shadow offset
          shadowOpacity: 0.5, // iOS shadow opacity
          shadowRadius: 3.84, // iOS shadow radius
          elevation: 8, // Android shadow
        }}
        className="flex w-[220px] flex-row items-center justify-center rounded-full bg-neutral-900 py-3 dark:bg-neutral-100">
        <Animated.View style={{ transform: [{ rotate: spin }] }}>
          <Icon name="RefreshCw" size={18} color={colors.invert} />
        </Animated.View>
        <Text className="ml-3 text-base font-medium text-white dark:text-neutral-900">
          {isBusinessMode ? 'Switch to travelling' : 'Switch to hosting'}
        </Text>
      </Pressable>
    </View>
  );
};

export default BusinessSwitch;

// components/Button.tsx
import { Link, router } from 'expo-router';
import React from 'react';
import { Text, ActivityIndicator, TouchableOpacity, View, Pressable } from 'react-native';

import Icon, { IconName } from './Icon';

type RoundedOption = 'none' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'full';

interface ButtonProps {
  title?: string;
  onPress?: () => void;
  loading?: boolean;
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  size?: 'small' | 'medium' | 'large';
  rounded?: RoundedOption;
  href?: string;
  className?: string;
  textClassName?: string;
  disabled?: boolean;
  iconStart?: IconName;
  iconEnd?: IconName;
  iconSize?: number;
  iconColor?: string;
  iconClassName?: string;
}

export const Button: React.FC<ButtonProps> = ({
  title,
  onPress,
  loading = false,
  variant = 'primary',
  size = 'medium',
  rounded = 'lg',
  href,
  className = '',
  textClassName = '',
  disabled = false,
  iconStart,
  iconEnd,
  iconSize,
  iconColor,
  iconClassName = '',
  ...props
}) => {
  const buttonStyles = {
    primary: 'bg-highlight',
    secondary: 'bg-light-secondary dark:bg-dark-secondary',
    outline: 'border border-black dark:border-white bg-transparent',
    ghost: 'bg-transparent',
  };

  const buttonSize = {
    small: 'py-2',
    medium: 'py-3',
    large: 'py-5',
  };

  const roundedStyles = {
    none: 'rounded-none',
    xs: 'rounded-xs',
    sm: 'rounded-sm',
    md: 'rounded-md',
    lg: 'rounded-lg',
    xl: 'rounded-xl',
    full: 'rounded-full',
  };

  const textColor =
    variant === 'outline' || variant === 'secondary' || variant === 'ghost'
      ? 'text-black dark:text-white'
      : 'text-white dark:text-black';
  const disabledStyle = disabled ? 'opacity-50' : '';

  // Default icon sizes based on button size
  const getIconSize = () => {
    if (iconSize) return iconSize;

    switch (size) {
      case 'small':
        return 16;
      case 'medium':
        return 18;
      case 'large':
        return 20;
      default:
        return 18;
    }
  };

  // Default icon color based on variant
  const getIconColor = () => {
    if (iconColor) return iconColor;

    // return variant === 'outline' || variant === 'secondary' || variant === 'ghost'
    //   ? '#000000' // highlight color
    //   : '#FFFFFF'; // white
  };

  const ButtonContent = (
    <>
      {loading ? (
        <ActivityIndicator
          color={
            variant === 'outline' || variant === 'secondary' || variant === 'ghost'
              ? '#39A845'
              : '#fff'
          }
        />
      ) : (
        <View className="flex-row items-center justify-center">
          {iconStart && (
            <Icon
              name={iconStart}
              size={getIconSize()}
              color={getIconColor()}
              className={`mr-2 ${iconClassName} `}
            />
          )}

          <Text className={`${textColor} font-medium ${textClassName}`}>{title}</Text>

          {iconEnd && (
            <Icon
              name={iconEnd}
              size={getIconSize()}
              color={getIconColor()}
              className={`ml-2 ${iconClassName}`}
            />
          )}
        </View>
      )}
    </>
  );

  if (href) {
    return (
      <TouchableOpacity
        disabled={loading || disabled}
        activeOpacity={0.8}
        className={`relative px-4 ${buttonStyles[variant]} ${buttonSize[size]} ${roundedStyles[rounded]} items-center justify-center ${disabledStyle} ${className}`}
        {...props}
        onPress={() => {
          router.push(href);
        }}>
        {ButtonContent}
      </TouchableOpacity>
    );
  }

  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={loading || disabled}
      activeOpacity={0.8}
      className={`relative px-4 ${buttonStyles[variant]} ${buttonSize[size]} ${roundedStyles[rounded]} items-center justify-center ${disabledStyle} ${className}`}
      {...props}>
      {ButtonContent}
    </TouchableOpacity>
  );
};

import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { LinearGradient } from 'expo-linear-gradient';
import { Link, router } from 'expo-router';
import {
  View,
  Text,
  Image,
  Pressable,
  ImageBackground,
  TouchableOpacity,
  ViewStyle,
  Dimensions,
  ImageSourcePropType,
} from 'react-native';

import { Button } from './Button';
import Favorite from './Favorite';
import Icon from './Icon';
import ThemedText from './ThemedText';

import useThemeColors from '@/app/contexts/ThemeColors';
import useShadow, { shadowPresets } from '@/utils/useShadow';

const { width: windowWidth } = Dimensions.get('window');
interface CardProps {
  title: string;
  description?: string;
  hasShadow?: boolean;
  image: string | ImageSourcePropType;
  href?: string;
  onPress?: () => void;
  variant?: 'classic' | 'overlay' | 'compact' | 'minimal';
  className?: string;
  button?: string;
  onButtonPress?: () => void;
  price?: string;
  rating?: number;
  badge?: string;
  badgeColor?: string;
  icon?: string;
  iconColor?: string;
  imageHeight?: number;
  showOverlay?: boolean;
  hasFavorite?: boolean;
  overlayGradient?: readonly [string, string];
  width?: any;
  rounded?: 'none' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | 'full';
  children?: React.ReactNode;
  style?: ViewStyle;
}

const Card: React.FC<CardProps> = ({
  title,
  description,
  image,
  hasShadow = false,
  href,
  onPress,
  variant = 'classic',
  className = 'w-full',
  button,
  onButtonPress,
  price,
  rating,
  badge,
  hasFavorite = false,
  badgeColor = '#000000',
  imageHeight = 200,
  showOverlay = true,
  overlayGradient = ['transparent', 'rgba(0,0,0,0.3)'] as readonly [string, string],
  rounded = 'lg',
  width = '100%',
  children,
  style,
  ...props
}) => {
  const handlePress = () => {
    if (onPress) {
      onPress();
    }
  };

  const getRoundedClass = () => {
    switch (rounded) {
      case 'none':
        return 'rounded-none';
      case 'sm':
        return 'rounded-sm';
      case 'md':
        return 'rounded-md';
      case 'lg':
        return 'rounded-lg';
      case 'xl':
        return 'rounded-xl';
      case '2xl':
        return 'rounded-2xl';
      case 'full':
        return 'rounded-full';
      default:
        return 'rounded-lg';
    }
  };

  const renderBadge = () => {
    if (!badge) return null;
    return (
      <View
        className={`absolute left-2 top-2 z-10 rounded-full bg-white/70 px-2 py-1 dark:bg-black/70 `}>
        <ThemedText className=" text-xs font-medium">{badge}</ThemedText>
      </View>
    );
  };
  const colors = useThemeColors();
  const renderRating = () => {
    if (!rating) return null;
    return (
      <View className="flex-row items-center ">
        <MaterialIcons name="star" size={10} color={colors.text} />
        <ThemedText className="ml-0 text-xs text-gray-500 dark:text-gray-300">{rating}</ThemedText>
      </View>
    );
  };

  const renderPrice = () => {
    if (!price) return null;
    return (
      <ThemedText
        className={`text-xs  ${variant === 'overlay' ? 'text-white' : 'text-gray-500 dark:text-gray-300'}`}>
        {price}
      </ThemedText>
    );
  };

  const renderContent = () => {
    const cardContent = (
      <View
        className={`flex-1 ${className}`}
        style={[
          hasShadow && {
            ...shadowPresets.small,
          },
          style,
        ]}>
        <View className="relative">
          {hasFavorite && (
            <View className="absolute right-3 top-3 z-50">
              <Favorite initialState={false} isWhite productName={title} size={24} />
            </View>
          )}
          {variant === 'overlay' ? (
            <ImageBackground
              source={typeof image === 'string' ? { uri: image } : image}
              className={`w-full overflow-hidden ${getRoundedClass()}`}
              style={{ height: imageHeight || 200 }}>
              {showOverlay && (
                <LinearGradient
                  colors={overlayGradient}
                  className="relative flex h-full w-full flex-col justify-end">
                  <View className="absolute bottom-0 left-0 right-0 p-4">
                    <Text className="text-base font-bold text-white">{title}</Text>
                    {description && (
                      <Text numberOfLines={1} className="text-xs text-white">
                        {description}
                      </Text>
                    )}
                    {(price || rating) && (
                      <View className="mt-1 flex-row items-center justify-start">
                        {renderPrice()}
                        {renderRating()}
                      </View>
                    )}
                  </View>
                </LinearGradient>
              )}
            </ImageBackground>
          ) : (
            <View
              className={`${getRoundedClass()} bg-neutral-200 dark:bg-dark-secondary `}
              style={shadowPresets.small}>
              <Image
                source={typeof image === 'string' ? { uri: image } : image}
                className={`w-full ${getRoundedClass()}`}
                style={{ height: imageHeight || 200 }}
              />
              {children}
            </View>
          )}
          {renderBadge()}
        </View>

        {variant !== 'overlay' && (
          <View className="w-full flex-1 py-2 ">
            <ThemedText className="text-sm font-medium">{title}</ThemedText>

            {description && (
              <ThemedText
                numberOfLines={1}
                className="mb-px text-xs text-gray-500 dark:text-gray-300">
                {description}
              </ThemedText>
            )}
            {(price || rating) && (
              <View className="mr-auto mt-1 flex-row items-center rounded-full bg-light-secondary px-2 py-1 dark:bg-dark-secondary">
                {renderPrice()}
                <View className="mx-1" />
                {renderRating()}
              </View>
            )}

            {button && (
              <Button className="mt-3" title={button} size="small" onPress={onButtonPress} />
            )}
          </View>
        )}
      </View>
    );

    if (href) {
      return (
        <TouchableOpacity
          className={`${variant === 'overlay' ? '!h-auto' : ''} ${className}`}
          activeOpacity={0.8}
          onPress={() => router.push(href)}
          style={{ width, ...style }}>
          {cardContent}
        </TouchableOpacity>
      );
    }

    return (
      <TouchableOpacity
        className={`${variant === 'overlay' ? '!h-auto' : ''} ${className}`}
        activeOpacity={0.8}
        onPress={handlePress}
        style={{ width, ...style }}>
        {cardContent}
      </TouchableOpacity>
    );
  };

  return renderContent();
};

export default Card;

import { Link } from 'expo-router';
import React, { ReactNode } from 'react';
import {
  View,
  ViewStyle,
  ImageBackground,
  ImageSourcePropType,
  StyleSheet,
  Image,
  Platform,
  TouchableOpacity,
} from 'react-native';

interface CustomCardProps {
  children: ReactNode;
  rounded?: 'none' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | 'full';
  padding?: 'none' | 'sm' | 'md' | 'lg' | 'xl';
  shadow?: 'none' | 'sm' | 'md' | 'lg' | 'xl';
  border?: boolean;
  borderColor?: string;
  background?: boolean;
  elevation?: boolean;
  className?: string;
  style?: ViewStyle;
  backgroundImage?: string;
  backgroundImageStyle?: ViewStyle;
  overlayColor?: string;
  overlayOpacity?: number;
  horizontal?: boolean;
  onPress?: () => void;
  href?: string;
}

const CustomCard: React.FC<CustomCardProps> = ({
  children,
  rounded = 'lg',
  padding = 'md',
  shadow = 'none',
  border = false,
  borderColor,
  background = true,
  elevation = true,
  className = '',
  style,
  backgroundImage,
  backgroundImageStyle,
  overlayColor = 'black',
  overlayOpacity = 0.3,
  horizontal = false,
  onPress,
  href,
}) => {
  const getRoundedClass = () => {
    switch (rounded) {
      case 'none':
        return '';
      case 'sm':
        return 'rounded-sm';
      case 'md':
        return 'rounded-md';
      case 'lg':
        return 'rounded-lg';
      case 'xl':
        return 'rounded-xl';
      case '2xl':
        return 'rounded-2xl';
      case 'full':
        return 'rounded-full';
      default:
        return 'rounded-lg';
    }
  };

  const getPaddingClass = () => {
    switch (padding) {
      case 'none':
        return '';
      case 'sm':
        return 'p-2';
      case 'md':
        return 'p-4';
      case 'lg':
        return 'p-6';
      case 'xl':
        return 'p-8';
      default:
        return 'p-4';
    }
  };

  const getShadowClass = () => {
    // Only use shadow classes on iOS
    if (!elevation || Platform.OS === 'android') return '';

    switch (shadow) {
      case 'none':
        return '';
      case 'sm':
        return 'shadow-sm';
      case 'md':
        return 'shadow';
      case 'lg':
        return 'shadow-lg';
      case 'xl':
        return 'shadow-xl';
      default:
        return 'shadow';
    }
  };

  // Get elevation value for Android
  const getElevationStyle = (): ViewStyle => {
    if (!elevation || Platform.OS !== 'android' || shadow === 'none') {
      return {};
    }

    // Map shadow values to Android elevation values
    const elevationValues = {
      sm: 2,
      md: 4,
      lg: 8,
      xl: 16,
    };

    const elevationValue = elevationValues[shadow] || 4;

    return {
      elevation: elevationValue,
      shadowColor: 'rgba(0, 0, 0, 0.5)',
      //shadowOpacity: 0.1,
      shadowRadius: elevationValue / 2,
      shadowOffset: {
        height: elevationValue / 3,
        width: 0,
      },
    };
  };

  const getBorderClass = () => {
    if (!border) return '';
    return borderColor
      ? `border border-[${borderColor}]`
      : 'border border-black/10 dark:border-white/10';
  };

  const getBackgroundClass = () => {
    if (!background) return '';
    return 'bg-light-primary dark:bg-dark-primary';
  };

  // Render the card with or without background image
  const renderCardContent = () => {
    const cardClasses = `
            w-full
            overflow-hidden
            ${getRoundedClass()}
            ${getPaddingClass()}
            ${getShadowClass()}
            ${getBorderClass()}
            ${!backgroundImage && getBackgroundClass()}
        `;

    // Combine regular style with elevation for Android
    const combinedStyle = {
      ...style,
      ...getElevationStyle(),
    };

    const content = backgroundImage ? (
      <View
        className={`overflow-visible ${getRoundedClass()} ${getShadowClass()} ${className}`}
        style={style}>
        <ImageBackground
          className={`${getRoundedClass()} relative w-full overflow-hidden`}
          source={typeof backgroundImage === 'string' ? { uri: backgroundImage } : backgroundImage}
          imageStyle={{ borderRadius: getRoundedValue() }}
          style={combinedStyle}>
          {overlayOpacity > 0 && (
            <View
              className={`${getPaddingClass()} absolute inset-0`}
              style={{
                ...StyleSheet.absoluteFillObject,
                backgroundColor: overlayColor,
                opacity: overlayOpacity,
                borderRadius: getRoundedValue(),
              }}
            />
          )}
          <View>{children}</View>
        </ImageBackground>
      </View>
    ) : (
      <View
        className={`overflow-visible ${getRoundedClass()} ${getShadowClass()} ${cardClasses}  ${className} ${horizontal ? 'flex-row' : 'flex-col'}`}
        style={style}>
        {children}
      </View>
    );

    if (href) {
      return (
        <Link href={href} asChild>
          <TouchableOpacity activeOpacity={1}>{content}</TouchableOpacity>
        </Link>
      );
    }

    if (onPress) {
      return (
        <TouchableOpacity onPress={onPress} activeOpacity={1}>
          {content}
        </TouchableOpacity>
      );
    }

    return content;
  };

  // Get numeric border radius value for ImageBackground
  const getRoundedValue = () => {
    switch (rounded) {
      case 'none':
        return 0;
      case 'sm':
        return 2;
      case 'md':
        return 6;
      case 'lg':
        return 8;
      case 'xl':
        return 12;
      case '2xl':
        return 16;
      case 'full':
        return 9999;
      default:
        return 8;
    }
  };

  return <>{renderCardContent()}</>;
};

export default CustomCard;

import React, { useState } from 'react';
import { View, useWindowDimensions } from 'react-native';
import { CalendarList, DateData } from 'react-native-calendars';

import ThemedText from './ThemedText';

import useThemeColors from '@/app/contexts/ThemeColors';

interface DateRange {
  startDate?: string;
  endDate?: string;
}

interface DateRangeCalendarProps {
  onDateRangeChange?: (range: DateRange) => void;
  initialRange?: DateRange;
  minDate?: string;
  maxDate?: string;
  className?: string;
}

const DateRangeCalendar: React.FC<DateRangeCalendarProps> = ({
  onDateRangeChange,
  initialRange,
  minDate,
  maxDate,
  className = '',
}) => {
  const colors = useThemeColors();
  const { width: screenWidth } = useWindowDimensions();
  const [selectedRange, setSelectedRange] = useState<DateRange>(initialRange || {});

  // Calculate calendar width accounting for parent padding
  // SearchBar has px-global (24px on each side = 48px total)
  // Accordion has p-global (24px on each side = 48px total)
  const calendarWidth = screenWidth - 96; // 48px for SearchBar + 48px for accordion padding

  // Determine marking type based on selection state
  const getMarkingType = () => {
    if (selectedRange.startDate && selectedRange.endDate) {
      return 'period';
    }
    return undefined; // Use default marking for single selection
  };

  const handleDayPress = (day: DateData) => {
    const { dateString } = day;

    if (!selectedRange.startDate || (selectedRange.startDate && selectedRange.endDate)) {
      // Start new selection
      const newRange = { startDate: dateString, endDate: undefined };
      setSelectedRange(newRange);
      onDateRangeChange?.(newRange);
    } else if (selectedRange.startDate && !selectedRange.endDate) {
      // Complete the range
      const startDate = selectedRange.startDate;
      const endDate = dateString;

      // Ensure start date is before end date
      const newRange =
        startDate <= endDate ? { startDate, endDate } : { startDate: endDate, endDate: startDate };

      setSelectedRange(newRange);
      onDateRangeChange?.(newRange);
    }
  };

  const getMarkedDates = () => {
    const marked: any = {};

    if (selectedRange.startDate && selectedRange.endDate) {
      const start = new Date(selectedRange.startDate);
      const end = new Date(selectedRange.endDate);

      // Mark all dates in range
      for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
        const dateString = d.toISOString().split('T')[0];

        if (dateString === selectedRange.startDate) {
          marked[dateString] = {
            startingDay: true,
            color: colors.highlight,
            textColor: 'white',
          };
        } else if (dateString === selectedRange.endDate) {
          marked[dateString] = {
            endingDay: true,
            color: colors.highlight,
            textColor: 'white',
          };
        } else {
          marked[dateString] = {
            color: colors.highlight + '40',
            textColor: colors.text,
          };
        }
      }
    } else if (selectedRange.startDate) {
      // For single date selection, use standard selected styling
      marked[selectedRange.startDate] = {
        selected: true,
        selectedColor: colors.highlight,
        selectedTextColor: 'white',
      };
    }

    return marked;
  };

  const formatDateRange = () => {
    if (selectedRange.startDate && selectedRange.endDate) {
      const start = new Date(selectedRange.startDate);
      const end = new Date(selectedRange.endDate);
      const startFormatted = start.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      const endFormatted = end.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      return `${startFormatted} - ${endFormatted}`;
    } else if (selectedRange.startDate) {
      const start = new Date(selectedRange.startDate);
      return start.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    }
    return 'Select dates';
  };

  return (
    <View className={` ${className}`}>
      {/*<View className="mb-4">
        <ThemedText className="text-sm font-medium mb-2">Selected dates</ThemedText>
        <ThemedText className="text-lg font-semibold">{formatDateRange()}</ThemedText>
      </View>*/}

      <CalendarList
        horizontal
        pagingEnabled
        scrollEnabled
        showScrollIndicator={false}
        calendarWidth={calendarWidth}
        calendarHeight={350}
        onDayPress={handleDayPress}
        markingType={getMarkingType()}
        markedDates={getMarkedDates()}
        minDate={minDate}
        maxDate={maxDate}
        theme={{
          backgroundColor: 'transparent',
          calendarBackground: 'transparent',
          textSectionTitleColor: colors.placeholder,
          selectedDayBackgroundColor: colors.highlight,
          selectedDayTextColor: 'white',
          todayTextColor: colors.highlight,
          dayTextColor: colors.text,
          textDisabledColor: colors.placeholder,
          dotColor: colors.highlight,
          selectedDotColor: 'white',
          arrowColor: colors.text,
          disabledArrowColor: colors.placeholder,
          monthTextColor: colors.text,
          indicatorColor: colors.highlight,
          textDayFontFamily: 'System',
          textMonthFontFamily: 'System',
          textDayHeaderFontFamily: 'System',
          textDayFontWeight: '400',
