import React, { useState, useEffect } from 'react';
import {
  View,
  FlatList,
  Image,
  Dimensions,
  Pressable,
  StyleSheet,
  LayoutChangeEvent,
  ImageSourcePropType,
} from 'react-native';

import ThemedText from '@/components/ThemedText';

interface ImageCarouselProps {
  images: string[] | ImageSourcePropType[];
  width?: number;
  height?: number;
  showPagination?: boolean;
  paginationStyle?: 'dots' | 'numbers';
  onImagePress?: (index: number) => void;
  autoPlay?: boolean;
  autoPlayInterval?: number;
  loop?: boolean;
  className?: string;
  rounded?: 'none' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | 'full';
}

const ImageCarousel: React.FC<ImageCarouselProps> = ({
  images,
  width: propWidth,
  height = 200,
  showPagination = true,
  paginationStyle = 'dots',
  onImagePress,
  autoPlay = false,
  autoPlayInterval = 3000,
  loop = true,
  className = '',
  rounded = 'none',
}) => {
  const [containerWidth, setContainerWidth] = useState(propWidth || Dimensions.get('window').width);
  const [activeIndex, setActiveIndex] = useState(0);
  const flatListRef = React.useRef<FlatList>(null);

  const handleLayout = (event: LayoutChangeEvent) => {
    const { width } = event.nativeEvent.layout;
    setContainerWidth(width);
  };

  const getRoundedClass = () => {
    switch (rounded) {
      case 'none':
        return '';
      case 'sm':
        return 'rounded-sm';
      case 'md':
        return 'rounded-md';
      case 'lg':
        return 'rounded-lg';
      case 'xl':
        return 'rounded-xl';
      case '2xl':
        return 'rounded-2xl';
      case 'full':
        return 'rounded-full';
      default:
        return '';
    }
  };

  const handleImageChange = (contentOffsetX: number) => {
    const index = Math.round(contentOffsetX / containerWidth);
    setActiveIndex(index);
  };

  const handleImagePress = () => {
    if (onImagePress) {
      onImagePress(activeIndex);
    }
  };

  const renderPagination = () => {
    if (!showPagination || images.length <= 1) return null;

    return (
      <View className="absolute bottom-4 w-full flex-row justify-center">
        {paginationStyle === 'dots' ? (
          images.map((_, index) => (
            <View
              key={index}
              className={`mx-1 h-2 w-2 rounded-full ${
                index === activeIndex ? 'bg-white' : 'bg-white/40'
              }`}
            />
          ))
        ) : (
          <View className="rounded-full bg-black/50 px-3 py-1">
            <ThemedText className="text-white">
              {activeIndex + 1} / {images.length}
            </ThemedText>
          </View>
        )}
      </View>
    );
  };

  const renderItem = ({ item, index }: { item: string | ImageSourcePropType; index: number }) => (
    <View style={{ width: containerWidth, height }}>
      <Image
        source={typeof item === 'string' ? { uri: item } : item}
        style={[
          styles.image,
          {
            width: containerWidth,
            height,
          },
        ]}
        resizeMode="cover"
      />
    </View>
  );

  return (
    <View
      className={`${getRoundedClass()} ${className}`}
      style={[
        styles.container,
        {
          height,
          overflow: 'hidden',
        },
      ]}
      onLayout={handleLayout}>
      <FlatList
        ref={flatListRef}
        data={images}
        horizontal
        pagingEnabled
        showsHorizontalScrollIndicator={false}
        keyExtractor={(_, index) => index.toString()}
        renderItem={renderItem}
        onMomentumScrollEnd={(e) => {
          const contentOffsetX = e.nativeEvent.contentOffset.x;
          handleImageChange(contentOffsetX);
        }}
        style={{ height }}
        contentContainerStyle={{ width: containerWidth * images.length }}
      />
      {renderPagination()}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    position: 'relative',
  },
  image: {
    backgroundColor: '#f0f0f0',
  },
});

export default ImageCarousel;

import { router } from 'expo-router';
import React, { ReactNode, useState, useRef, useEffect, Children, isValidElement } from 'react';
import { View, Pressable, ScrollView, Animated } from 'react-native';
import { useSafeAreaInsets } from 'react-native-safe-area-context';

import { Button } from '@/components/Button';
import Header from '@/components/Header';
import Icon from '@/components/Icon';
import ThemedText from '@/components/ThemedText';

// Step component that will be used as children
export interface StepProps {
  title: string;
  optional?: boolean;
  children: ReactNode;
}

export const Step: React.FC<StepProps> = ({ children }) => {
  return <>{children}</>; // Just render children, this is mainly for type safety
};

// Add this to help with type checking
const isStepComponent = (child: any): child is React.ReactElement<StepProps> => {
  return (
    isValidElement(child) &&
    (child.type === Step || (typeof child.type === 'function' && child.type.name === 'Step'))
  );
};

interface StepData {
  key: string;
  title: string;
  optional?: boolean;
  component: ReactNode;
}

interface MultiStepProps {
  children: ReactNode;
  onComplete: () => void;
  onClose?: () => void;
  showHeader?: boolean;
  showStepIndicator?: boolean;
  className?: string;
  onStepChange?: (nextStep: number) => boolean;
}

export default function MultiStep({
  children,
  onComplete,
  onClose,
  showHeader = true,
  showStepIndicator = true,
  className = '',
  onStepChange,
}: MultiStepProps) {
  // Filter and validate children to only include Step components
  const validChildren = Children.toArray(children).filter(isStepComponent);

  // Extract step data from children
  const steps: StepData[] = validChildren.map((child, index) => {
    const {
      title,
      optional,
      children: stepContent,
    } = (child as React.ReactElement<StepProps>).props;
    return {
      key: `step-${index}`,
      title: title || `Step ${index + 1}`,
      optional,
      component: stepContent,
    };
  });

  // Ensure we have at least one step
  if (steps.length === 0) {
    steps.push({
      key: 'empty-step',
      title: 'Empty',
      component: (
        <View>
          <ThemedText>No steps provided</ThemedText>
        </View>
      ),
    });
  }

  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const currentStep = steps[currentStepIndex];
  const isLastStep = currentStepIndex === steps.length - 1;
  const isFirstStep = currentStepIndex === 0;

  // Animation values
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const slideAnim = useRef(new Animated.Value(50)).current;
  const progressAnims = useRef(steps.map(() => new Animated.Value(0))).current;

  useEffect(() => {
    // Reset and start fade/slide animations
    fadeAnim.setValue(0);
    slideAnim.setValue(50);

    Animated.parallel([
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 200,
        useNativeDriver: true,
      }),
      Animated.timing(slideAnim, {
        toValue: 0,
        duration: 200,
        useNativeDriver: true,
      }),
    ]).start();

    // Animate progress indicators
    steps.forEach((_, index) => {
      Animated.timing(progressAnims[index], {
        toValue: index <= currentStepIndex ? 1 : 0,
        duration: 300,
        useNativeDriver: false,
      }).start();
    });
  }, [currentStepIndex]);

  const handleNext = () => {
    if (isLastStep) {
      onComplete();
    } else {
      const nextStep = currentStepIndex + 1;
      const canProceed = onStepChange ? onStepChange(nextStep) : true;

      if (canProceed) {
        setCurrentStepIndex(nextStep);
      }
    }
  };

  const handleBack = () => {
    if (!isFirstStep) {
      setCurrentStepIndex(currentStepIndex - 1);
    }
  };

  const handleSkip = () => {
    if (currentStep.optional && !isLastStep) {
      setCurrentStepIndex(currentStepIndex + 1);
    }
  };

  const handleClose = () => {
    if (onClose) {
      onClose();
    }
  };

  const insets = useSafeAreaInsets();

  return (
    <View
      style={{ paddingBottom: insets.bottom }}
      className={`flex-1 bg-light-primary dark:bg-dark-primary ${className}`}>
      {showHeader && (
        <Header
          rightComponents={[
            onClose ? (
              <Pressable
                key="close"
                onPress={() => router.back()}
                className="rounded-full p-2 active:bg-light-secondary dark:active:bg-dark-secondary"
                hitSlop={8}>
                <Icon name="X" size={24} className="text-light-text dark:text-dark-text" />
              </Pressable>
            ) : undefined,
          ]}
          leftComponent={[
            currentStep.optional && !isLastStep && (
              <Button key="skip" title="Skip" variant="ghost" onPress={handleSkip} size="small" />
            ),
            !isFirstStep && (
              <Icon
                name="ArrowLeft"
                key="back"
                size={24}
                className="text-light-text dark:text-dark-text"
                onPress={handleBack}
              />
            ),
          ]}
        />
      )}

      {/* Step Content */}
      <Animated.View
        className="flex-1"
        style={{
          opacity: fadeAnim,
          transform: [{ translateY: slideAnim }],
        }}>
        <ScrollView
          contentContainerStyle={{ flexGrow: 1 }}
          keyboardShouldPersistTaps="handled"
          showsVerticalScrollIndicator={false}>
          {currentStep.component}
        </ScrollView>
      </Animated.View>

      {/* Step Indicators */}
      {showStepIndicator && (
        <View className="flex-row justify-center px-4 py-3">
          {steps.map((_, index) => (
            <Animated.View
              key={index}
              className="mx-1 h-1 flex-1 overflow-hidden rounded-full bg-neutral-500 dark:bg-dark-secondary"
              style={{
                width: 20,
                opacity: index === currentStepIndex ? 1 : 0.5,
              }}>
              <Animated.View
                className="bg-light-accent dark:bg-dark-accent h-full"
                style={{
                  width: progressAnims[index].interpolate({
                    inputRange: [0, 1],
                    outputRange: ['0%', '100%'],
                  }),
                }}
              />
            </Animated.View>
          ))}
        </View>
      )}

      {/* Bottom Navigation */}
      <View className="border-t border-light-secondary px-4 py-3 dark:border-dark-secondary">
        <Button
          title={isLastStep ? 'Complete' : 'Next'}
          onPress={handleNext}
          className="w-full"
          size="large"
          textClassName="text-white"
        />
      </View>
    </View>
  );
}

import * as ImagePicker from 'expo-image-picker';
import React, { useState } from 'react';
import { View, Image, Pressable, Dimensions, Text, ScrollView } from 'react-native';

import { CardScroller } from './CardScroller';
import Icon from './Icon';

interface MultipleImagePickerProps {
  onImageSelect?: (uri: string) => void;
  hasMainImage?: boolean;
}

const windowWidth = Dimensions.get('window').width;

export const MultipleImagePicker: React.FC<MultipleImagePickerProps> = ({
  onImageSelect,
  hasMainImage = true,
}) => {
  const [mainImage, setMainImage] = useState<string | null>(null);
  const [additionalImages, setAdditionalImages] = useState<string[]>([]);

  const handleDelete = (index?: number) => {
    if (typeof index === 'undefined') {
      setMainImage(null);
    } else {
      setAdditionalImages((prev) => prev.filter((_, i) => i !== index));
    }
  };

  const pickImage = async (isMain: boolean = false) => {
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.All,
      allowsEditing: false,
      aspect: [5, 4],
      quality: 1,
      allowsMultipleSelection: true,
      selectionLimit: isMain ? 1 : 4,
    });

    if (!result.canceled) {
      if (isMain) {
        const uri = result.assets[0].uri;
        setMainImage(uri);
        onImageSelect?.(uri);
      } else {
        const newImages = result.assets.map((asset) => asset.uri);
        setAdditionalImages((prev) => {
          const combined = [...prev, ...newImages];
          return combined.slice(0, 4); // Limit to 4 images
        });
      }
    }
  };

  return (
    <>
      <Text className="mb-2 text-sm dark:text-white">Images</Text>
      <CardScroller>
        {mainImage ? (
          <View className="relative">
            <Pressable
              onPress={() => pickImage(true)}
              className="relative flex h-28 w-28 flex-col items-center justify-center overflow-hidden rounded-xl border border-black dark:border-white"
              android_ripple={{ color: 'rgba(0,0,0,0.3)', borderless: false }}>
              <Image className="h-full w-full" source={{ uri: mainImage }} />
            </Pressable>
            <Pressable
              onPress={() => handleDelete()}
              className="absolute right-2 top-2 h-7 w-7 items-center justify-center rounded-lg bg-white dark:bg-dark-secondary">
              <Icon name="Trash2" size={18} />
            </Pressable>
          </View>
        ) : (
          hasMainImage && (
            <Pressable
              onPress={() => pickImage(true)}
              className="relative flex h-28 w-28 flex-col items-center justify-center rounded-xl border border-black p-4 dark:border-white"
              android_ripple={{ color: 'rgba(0,0,0,0.3)', borderless: false }}>
              <Icon name="Camera" size={24} />
              <Text className="absolute bottom-4 w-full text-center text-xs text-black dark:text-white">
                Main photo
              </Text>
            </Pressable>
          )
        )}
        {[...Array(4)].map((_, index) => {
          const image = additionalImages[index];
          return (
            <View key={index} className="relative">
              {image ? (
                <>
                  <Pressable
                    onPress={() => pickImage(false)}
                    className="relative flex h-28 w-28 flex-col items-center justify-center overflow-hidden rounded-xl border border-black dark:border-white"
                    android_ripple={{ color: 'rgba(0,0,0,0.3)', borderless: false }}>
                    <Image className="h-full w-full" source={{ uri: image }} />
                  </Pressable>
                  <Pressable
                    onPress={() => handleDelete(index)}
                    className="absolute right-2 top-2 h-7 w-7 items-center justify-center rounded-lg bg-white">
                    <Icon name="Trash2" size={18} />
                  </Pressable>
                </>
              ) : (
                <Pressable
                  onPress={() => pickImage(false)}
                  className="flex h-28 w-28 flex-col items-center justify-center rounded-xl border border-black p-4 opacity-40 dark:border-white"
                  android_ripple={{ color: 'rgba(0,0,0,0.3)', borderless: false }}>
                  <Icon name="Plus" size={24} />
                </Pressable>
              )}
            </View>
          );
        })}
      </CardScroller>
    </>
  );
};

