import React, { useState, useRef, ReactNode, useEffect } from 'react';
import {
  View,
  ScrollView,
  Animated,
  Dimensions,
  TouchableOpacity,
  ViewStyle,
  BackHandler,
} from 'react-native';

import AnimatedView from './AnimatedView';
import ThemedText from './ThemedText';

type ThemeTabsProps = {
  children: ReactNode;
  headerComponent?: ReactNode;
  footerComponent?: ReactNode;
  type?: 'scrollview' | 'fixed';
  className?: string;
  style?: ViewStyle;
  scrollEnabled?: boolean;
};

type ThemeTabProps = {
  name: string;
  children: ReactNode;
  type?: 'scrollview' | 'flatlist' | 'view';
};

const { width: SCREEN_WIDTH } = Dimensions.get('window');

export const ThemeTab: React.FC<ThemeTabProps> = ({ children }) => {
  return (
    <View className="" style={{ width: SCREEN_WIDTH, height: '100%' }}>
      {children}
    </View>
  );
};

const ThemeTabs: React.FC<ThemeTabsProps> = ({
  children,
  headerComponent,
  footerComponent,
  style,
  type = 'fixed',
  scrollEnabled = true,
}) => {
  const [activeTab, setActiveTab] = useState(0);
  const scrollX = useRef(new Animated.Value(0)).current;
  const tabContentRef = useRef<ScrollView>(null);
  const mainScrollRef = useRef<ScrollView>(null);

  // Add back button handler
  {
    /*useEffect(() => {
        const backHandler = BackHandler.addEventListener('hardwareBackPress', () => {
            if (activeTab > 0) {
                handleTabPress(activeTab - 1);
                return true; // Prevent default back action
            }
            return false; // Allow default back action
        });

        return () => backHandler.remove();
    }, [activeTab]);*/
  }

  // Filter out only ThemeTab components from children
  const tabs = React.Children.toArray(children).filter(
    (child) => React.isValidElement(child) && child.type === ThemeTab
  );

  const handleTabPress = (index: number) => {
    setActiveTab(index);
    tabContentRef.current?.scrollTo({
      x: index * SCREEN_WIDTH,
      animated: true,
    });
  };

  const handleScroll = Animated.event([{ nativeEvent: { contentOffset: { x: scrollX } } }], {
    useNativeDriver: false,
  });

  const handleScrollEnd = (event: any) => {
    const position = event.nativeEvent.contentOffset.x;
    const index = Math.round(position / SCREEN_WIDTH);
    setActiveTab(index);
  };

  // Calculate sticky header indices correctly based on whether headerComponent exists
  const stickyHeaderIndices = headerComponent ? [1] : [0];

  return (
    <View className="flex-1 bg-light-primary dark:bg-dark-primary">
      <ScrollView
        ref={mainScrollRef}
        stickyHeaderIndices={stickyHeaderIndices}
        showsVerticalScrollIndicator={false}
        contentContainerStyle={{ flexGrow: 1 }}
        className="flex-1">
        {/* Header Component - Will scroll up */}
        {headerComponent && <View>{headerComponent}</View>}

        {/* Tab Bar - This will be sticky */}
        <View className="z-10">
          {type === 'scrollview' ? (
            <ScrollView
              showsHorizontalScrollIndicator={false}
              horizontal
              className="h-[48px] flex-row border-b border-light-secondary bg-light-primary dark:border-white/20 dark:bg-dark-primary">
              {tabs.map((tab, index) => {
                if (!React.isValidElement(tab)) return null;
                return (
                  <Animated.View key={index}>
                    <TouchableOpacity
                      activeOpacity={0.7}
                      className="relative h-full items-center justify-center px-4"
                      onPress={() => handleTabPress(index)}>
                      <ThemedText
                        className={`text-base ${activeTab === index ? 'text-highlight' : ''}`}>
                        {tab.props.name}
                      </ThemedText>
                      {activeTab === index && (
                        <View className="absolute bottom-0 h-[2px] w-full bg-highlight" />
                      )}
                    </TouchableOpacity>
                  </Animated.View>
                );
              })}
            </ScrollView>
          ) : (
            <View className="h-[48px] flex-row border-b border-light-secondary bg-light-primary dark:border-white/20 dark:bg-dark-primary">
              {tabs.map((tab, index) => {
                if (!React.isValidElement(tab)) return null;
                return (
                  <Animated.View key={index} className="flex-1">
                    <TouchableOpacity
                      activeOpacity={0.7}
                      className="relative flex-1 items-center justify-center px-3"
                      onPress={() => handleTabPress(index)}>
                      <ThemedText
                        className={`text-base ${activeTab === index ? 'text-highlight' : ''}`}>
                        {tab.props.name}
                      </ThemedText>
                      {activeTab === index && (
                        <View className="absolute bottom-0 h-[2px] w-full bg-highlight" />
                      )}
                    </TouchableOpacity>
                  </Animated.View>
                );
              })}
            </View>
          )}
        </View>

        {/* Tab Content - Horizontal scrollable area */}
        <View className="flex-1">
          {scrollEnabled ? (
            <ScrollView
              ref={tabContentRef}
              horizontal
              pagingEnabled
              showsHorizontalScrollIndicator={false}
              onScroll={handleScroll}
              scrollEventThrottle={16}
              onMomentumScrollEnd={handleScrollEnd}
              className="flex-1"
              scrollEnabled={scrollEnabled}>
              {tabs}
            </ScrollView>
          ) : (
            <AnimatedView
              key={activeTab}
              duration={600}
              animation="fadeIn"
              className="flex-1"
              style={{ width: SCREEN_WIDTH }}>
              {tabs[activeTab]}
            </AnimatedView>
          )}
        </View>

        {footerComponent && <View>{footerComponent}</View>}
      </ScrollView>
    </View>
  );
};

export default ThemeTabs;

import { useTheme } from 'app/contexts/ThemeContext';
import React, { useState, useRef, useEffect } from 'react';
import { View, Animated, TouchableOpacity } from 'react-native';

import Icon from './Icon';

import useThemeColors from '@/app/contexts/ThemeColors';

interface ThemeToggleProps {
  value?: boolean;
  onChange?: (value: boolean) => void;
  className?: string;
}

const ThemeToggle: React.FC<ThemeToggleProps> = ({ value, onChange, className = '' }) => {
  const { isDark, toggleTheme } = useTheme();
  const colors = useThemeColors();

  // Use controlled or uncontrolled mode
  const isControlled = value !== undefined;
  const isActive = isControlled ? value : isDark;

  // Create animation value - initialize based on current state
  const slideAnim = useRef(new Animated.Value(isActive ? 1 : 0)).current;

  // Update animation when theme changes - simplified approach
  useEffect(() => {
    Animated.timing(slideAnim, {
      toValue: isActive ? 1 : 0,
      duration: 200,
      useNativeDriver: true,
    }).start();
  }, [isActive, slideAnim]);

  const handlePress = () => {
    // Handle controlled or uncontrolled mode
    if (isControlled && onChange) {
      onChange(!value);
    } else if (!isControlled) {
      toggleTheme();
    }
  };

  return (
    <TouchableOpacity
      activeOpacity={0.7}
      onPress={handlePress}
      className={`flex-row items-center py-1 ${className}`}>
      <View className="h-10 w-20 flex-row items-center justify-between rounded-full">
        <View className="absolute h-full w-full rounded-full bg-light-secondary dark:bg-dark-secondary" />

        {/* Sun icon on left */}
        <View className="z-10 ml-1 h-8 w-8 items-center justify-center">
          <Icon name="Sun" size={16} color={isActive ? colors.placeholder : colors.text} />
        </View>

        {/* Moon icon on right */}
        <View className="z-10 mr-1 h-8 w-8 items-center justify-center">
          <Icon name="Moon" size={16} color={!isActive ? colors.placeholder : colors.text} />
        </View>

        {/* Animated thumb */}
        <Animated.View
          style={{
            transform: [
              {
                translateX: slideAnim.interpolate({
                  inputRange: [0, 1],
                  outputRange: [4, 43], // Move from left (1px) to right (41px)
                }),
              },
            ],
            position: 'absolute',
            top: 4,
          }}
          className="h-8 w-8 rounded-full bg-white shadow-sm dark:bg-dark-primary"
        />
      </View>
    </TouchableOpacity>
  );
};

export default ThemeToggle;

import React from 'react';
import { View, Pressable } from 'react-native';

import Icon from '../Icon';
import ThemedText from '../ThemedText';

import useThemeColors from '@/app/contexts/ThemeColors';

interface CheckboxProps {
  label: string;
  checked?: boolean;
  onChange?: (checked: boolean) => void;
  error?: string;
  className?: string;
}

const Checkbox: React.FC<CheckboxProps> = ({
  label,
  checked = false,
  onChange,
  error,
  className = '',
}) => {
  const colors = useThemeColors();

  // Internal state if no onChange provided (for mockups)
  const [internalChecked, setInternalChecked] = React.useState(checked);

  // Use either the controlled prop or internal state
  const isChecked = onChange ? checked : internalChecked;

  const handlePress = () => {
    if (onChange) {
      onChange(!isChecked);
    } else {
      setInternalChecked(!internalChecked);
    }
  };

  return (
    <View className={`mb-global ${className}`}>
      <Pressable onPress={handlePress} className="flex-row items-center">
        <View
          className={`
          flex h-6 w-6 items-center justify-center rounded border
          ${isChecked ? 'bg-primary border-highlight' : 'border-black/40 dark:border-white/40'}
          ${error ? 'border-red-500' : ''}
        `}>
          {isChecked && (
            <View className="h-full w-full items-center justify-center rounded border-[2px] border-light-primary bg-highlight dark:border-dark-primary">
              <Icon name="Check" size={14} color="#fff" />
            </View>
          )}
        </View>
        <ThemedText className="ml-2">{label}</ThemedText>
      </Pressable>

      {error && <ThemedText className="mt-1 text-xs text-red-500">{error}</ThemedText>}
    </View>
  );
};

