import React, { useState } from 'react';
import { View, Pressable, Text, StyleProp, ViewStyle } from 'react-native';

import ThemedText from '../ThemedText';

interface CounterProps {
  label?: string;
  value?: number;
  onChange?: (value: number | undefined) => void;
  min?: number;
  max?: number;
  className?: string;
  style?: StyleProp<ViewStyle>;
}

export default function Counter({
  label,
  value: controlledValue,
  onChange,
  min = 0,
  max = 99,
  className,
  style,
}: CounterProps) {
  const [internalValue, setInternalValue] = useState<number | undefined>(undefined);

  // Handle controlled and uncontrolled modes
  const isControlled = controlledValue !== undefined;
  const value = isControlled ? controlledValue : internalValue;

  const handleChange = (newValue: number | undefined) => {
    if (!isControlled) {
      setInternalValue(newValue);
    }
    onChange?.(newValue);
  };

  const increment = () => {
    if (value === undefined) {
      handleChange(1);
    } else if (value < max) {
      handleChange(value + 1);
    }
  };

  const decrement = () => {
    if (value === 1) {
      handleChange(undefined);
    } else if (value !== undefined && value > min) {
      handleChange(value - 1);
    }
  };

  return (
    <View className={`w-auto ${className}`} style={style}>
      <View className="w-full flex-row items-center justify-between">
        <View className="min-w-[100px] flex-row items-center justify-between overflow-hidden rounded-full bg-light-secondary p-1  dark:bg-dark-secondary">
          <Pressable
            onPress={decrement}
            className="h-8 w-8 items-center justify-center rounded-full bg-light-primary dark:bg-dark-primary">
            <ThemedText className="text-lg">-</ThemedText>
          </Pressable>

          <View className="min-w-[80px] items-center justify-center px-4">
            <ThemedText className="text-base font-medium">
              {value === undefined ? 'any' : value}
            </ThemedText>
          </View>

          <Pressable
            onPress={increment}
            className="h-8 w-8 items-center justify-center rounded-full bg-light-primary dark:bg-dark-primary">
            <ThemedText className="text-lg">+</ThemedText>
          </Pressable>
        </View>
      </View>
    </View>
  );
}

import React, { useState } from 'react';
import { View, Pressable, ViewStyle } from 'react-native';

import ThemedText from '../ThemedText';

import { cn } from '@/lib/utils';

interface FormTabProps {
  title: string;
  isActive?: boolean;
  onPress?: () => void;
}

export function FormTab({ title, isActive, onPress }: FormTabProps) {
  return (
    <Pressable
      onPress={onPress}
      className={`flex-1 rounded-xl px-4 py-2.5 ${isActive ? 'bg-light-primary shadow-lg dark:bg-light-primary' : 'bg-transparent'}`}>
      <ThemedText
        className={`text-center text-sm font-medium ${isActive ? 'text-black dark:text-black' : 'text-black dark:text-white'}`}>
        {title}
      </ThemedText>
    </Pressable>
  );
}

interface FormTabsProps {
  children: React.ReactElement<FormTabProps>[];
  defaultActiveTab?: string;
  onChange?: (tab: string) => void;
  className?: string;
  props?: any;
  style?: ViewStyle;
}

export default function FormTabs({
  children,
  defaultActiveTab,
  style,
  onChange,
  className = '',
}: FormTabsProps) {
  const [activeTab, setActiveTab] = useState(defaultActiveTab || children[0].props.title);

  return (
    <View
      className={`flex-row overflow-hidden rounded-xl bg-light-secondary p-1 dark:bg-dark-secondary ${className}`}
      style={style}>
      {React.Children.map(children, (child) => {
        return React.cloneElement(child, {
          isActive: activeTab === child.props.title,
          onPress: () => {
            setActiveTab(child.props.title);
            onChange?.(child.props.title);
          },
        });
      })}
    </View>
  );
}

import React, { useState, useRef } from 'react';
import {
  View,
  Pressable,
  Animated,
  Switch as RNSwitch,
  TouchableOpacity,
  StyleProp,
  ViewStyle,
} from 'react-native';

import Icon, { IconName } from '../Icon';
import ThemedText from '../ThemedText';

import useThemeColors from '@/app/contexts/ThemeColors';

interface SwitchProps {
  value?: boolean;
  onChange?: (value: boolean) => void;
  label?: string;
  description?: string;
  icon?: IconName;
  disabled?: boolean;
  className?: string;
  style?: StyleProp<ViewStyle>;
}

const Switch: React.FC<SwitchProps> = ({
  value,
  onChange,
  label,
  description,
  icon,
  disabled = false,
  className = '',
  style,
}) => {
  const colors = useThemeColors();
  const [isOn, setIsOn] = useState(value ?? false);
  const slideAnim = useRef(new Animated.Value((value ?? false) ? 1 : 0)).current;

  // Handle controlled vs uncontrolled state
  const isControlled = value !== undefined;
  const switchValue = isControlled ? value : isOn;

  const toggleSwitch = () => {
    if (disabled) return;

    const newValue = !switchValue;

    // Update internal state if uncontrolled
    if (!isControlled) {
      setIsOn(newValue);
    }

    // Call callback if provided
    onChange?.(newValue);

    // Animate the switch
    Animated.spring(slideAnim, {
      toValue: newValue ? 1 : 0,
      useNativeDriver: true,
      bounciness: 4,
      speed: 12,
    }).start();
  };

  return (
    <TouchableOpacity
      activeOpacity={0.7}
      onPress={toggleSwitch}
      disabled={disabled}
      className={`flex-row items-center py-1 ${disabled ? 'opacity-100' : ''} ${className}`}
      style={style}>
      {icon && (
        <View className="mr-3">
          <Icon name={icon} size={20} color={colors.text} />
        </View>
      )}

      <View className="flex-1">
        {label && <ThemedText className="text-base font-medium">{label}</ThemedText>}
        {description && (
          <ThemedText className="text-sm text-light-subtext dark:text-dark-subtext">
            {description}
          </ThemedText>
        )}
      </View>

      <View className="h-6 w-10 rounded-full">
        <View
          className={`absolute h-full w-full rounded-full ${switchValue ? 'bg-highlight' : 'bg-light-secondary dark:bg-white/40'}`}
        />
        <Animated.View
          style={{
            transform: [
              {
                translateX: slideAnim.interpolate({
                  inputRange: [0, 1.2],
                  outputRange: [1, 21],
                }),
              },
            ],
          }}
          className="my-0.5 h-5 w-5 rounded-full bg-white shadow-sm dark:bg-white"
        />
      </View>
    </TouchableOpacity>
  );
};

export default Switch;

import { Platform, ViewStyle } from 'react-native';

interface ShadowProps {
  elevation?: number;
  shadowColor?: string;
  shadowOpacity?: number;
  shadowRadius?: number;
  shadowOffset?: {
    width: number;
    height: number;
  };
}

/**
 * Hook to generate consistent shadow styles across the app
 * @param options - Shadow configuration options
 * @returns Shadow style object for React Native components
 */
export const useShadow = (options?: ShadowProps): ViewStyle => {
  const {
    elevation = 5,
    shadowColor = '#000',
    shadowOpacity = 0.15,
    shadowRadius = 3.84,
    shadowOffset = {
      width: 0,
      height: 2,
    },
  } = options || {};

  // iOS shadows
  const iosShadow: ViewStyle = {
    shadowColor,
    shadowOpacity,
    shadowRadius,
    shadowOffset,
  };

  // Android elevation
  const androidShadow: ViewStyle = {
    elevation,
  };

  // Return platform-specific shadow styles
  return Platform.OS === 'ios' ? iosShadow : { ...iosShadow, ...androidShadow };
};

/**
 * Preset shadow styles for common use cases
 */
export const shadowPresets = {
  small: useShadow({
    elevation: 3,
    shadowRadius: 2.5,
    shadowOffset: { width: 0, height: 1 },
  }),

  medium: useShadow({
    elevation: 8,
    shadowRadius: 5,
    shadowOffset: { width: 0, height: 3 },
  }),

  large: useShadow({
    elevation: 15,
    shadowRadius: 10.84,
    shadowOffset: { width: 0, height: 10 },
  }),

  card: useShadow({
    elevation: 4,
    shadowRadius: 3.84,
    shadowOffset: { width: 0, height: 2 },
  }),
};

export default useShadow;
